// lib/recurrence.ts
const cache = new Map<string, Date[]>();

export function computeUpcoming(
  template: RecurringTemplate,
  windowStart: Date,
  windowEnd: Date
): Date[] {
  const key = `${template.id}:${windowStart.toISOString()}:${windowEnd.toISOString()}`;
  if (cache.has(key)) return cache.get(key)!;
  const dates: Date[] = [];
  // ... compute dates based on frequency, startDate, endDate
  cache.set(key, dates);
  return dates;
}

export function invalidateOccurrenceCache(templateId?: string) {
  if (templateId) {
    for (const key of cache.keys()) {
      if (key.startsWith(templateId)) cache.delete(key);
    }
  } else {
    cache.clear();
  }
}

// In useRecurringTemplates hook
const remove = async (id: string, mode: 'single' | 'series', expenseId?: string) => {
  await db.transaction('rw', db.expenses, db.recurringTemplates, async () => {
    if (mode === 'single' && expenseId) {
      await db.expenses.update(expenseId, { recurringTemplateId: null });
    } else {
      await db.expenses.where('recurringTemplateId').equals(id).modify({ recurringTemplateId: null });
      await db.recurringTemplates.delete(id);
    }
  });
  invalidateOccurrenceCache(id);
};

