// lib/db.ts
import Dexie from 'dexie';

export const db = new Dexie('CashPulseDB');

db.version(1).stores({
  expenses: '++id, categoryId, date, paymentMethod',
  categories: '++id, name',
});

db.version(2).stores({
  expenses: '++id, categoryId, date, paymentMethod, recurringTemplateId',
  categories: '++id, name',
  recurringTemplates: '++id, categoryId, frequency, status, nextOccurrence',
}).upgrade(tx => {
  // Existing expenses get null recurringTemplateId by default
  return tx.table('expenses').toCollection().modify(exp => {
    if (exp.recurringTemplateId === undefined) exp.recurringTemplateId = null;
  });
});

