// db/queries.ts
import { db } from './cashpulse.db';
import type { RecurringTemplate, Expense } from './types';

export async function getUpcomingOccurrences(month: Date, limit = 5): Promise<UpcomingOccurrence[]> {
  const templates = await db.recurringTemplates
    .where('status').equals('active')
    .and(t => t.nextOccurrence <= endOfMonth(month))
    .sortBy('nextOccurrence');
  return templates.slice(0, limit).map(computeOccurrence);
}

export async function deleteTemplate(templateId: string): Promise<void> {
  await db.transaction('rw', [db.expenses, db.recurringTemplates], async () => {
    // Nullify FK on past expenses — preserve history
    await db.expenses.where('recurringTemplateId').equals(templateId)
      .modify({ recurringTemplateId: null });
    await db.recurringTemplates.delete(templateId);
  });
}

