// utils/validators.ts
export function validateRecurringTemplate(input: RecurringTemplateInput): ValidationResult {
  const errors: FieldError[] = [];
  if (input.amount <= 0 || input.amount > 99999.99) errors.push({ field: 'amount', message: 'Amount must be between $0.01 and $99,999.99' });
  if (!['weekly', 'monthly', 'yearly'].includes(input.frequency)) errors.push({ field: 'frequency', message: 'Select a frequency' });
  if (input.endDate && input.endDate <= input.startDate) errors.push({ field: 'endDate', message: 'End date must be after start date' });
  return { valid: errors.length === 0, errors };
}

